def replace_section(text: str, section: str) -> str:
    start = text.index('    <section class="notes-section section-block" id="notes"')
    end = text.index('\n\n    <section class="contact-section', start)
    return text[:start] + section + text[end:]


def patch_home(path: Path, section: str, css_href: str) -> None:
    text = path.read_text(encoding='utf-8')
    css_link = f'  <link rel="stylesheet" href="{css_href}">'
    if css_link not in text:
        marker = '  <link rel="stylesheet" href="assets/css/site.v3-1.css">' if path.name == 'index.html' and path.parent == ROOT else '  <link rel="stylesheet" href="../assets/css/site.v3-1.css">'
        text = text.replace(marker, marker + '\n' + css_link, 1)
    text = replace_section(text, section)
    path.write_text(text, encoding='utf-8')


(ROOT / 'notes/index.html').write_text(UA_HUB, encoding='utf-8')
(ROOT / 'ru/notes/index.html').write_text(RU_HUB, encoding='utf-8')
